## Section1(not reported)
## Problem1(A.6.6.24)
## Author()
## Institution()
## Language(en-US)

DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "niceTables.pl",
  "PGchoicemacros.pl",
  "contextForm.pl",
  "parserPopUp.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
Context()->noreduce('(-x)-y', '(-x)+y');
$actual_solution = Real(random(-9,9) + random(1,9)/10);
($m, $n) = (2..9)[NchooseK(8,2)];
$b = non_zero_random(-9,9,0.1);
$left = Formula("abs($m x + $b)")->reduce;
$right = Formula("$n x");
$right += $left->eval(x => $actual_solution) - $right->eval(x => $actual_solution);
if (random(0,1)) {
  $right = Formula("-$n x") - $right->eval(x => 0);
}
$right = $right->reduce;
$right = Formula("abs($right)");
$proposed_solution = random(0,1) ? $actual_solution : $actual_solution + non_zero_random(-3,3,0.1);
Context("LimitedNumeric");
$lefteval = Real($left->eval(x => $proposed_solution));
$righteval = Real($right->eval(x => $proposed_solution));
$dropdown = DropDown(["Yes, it is a solution.", "No, it is not a solution."], ($lefteval == $righteval) ? 0 : 1, showInStatic => 0);

############################################################
# Body
############################################################

BEGIN_PGML
Check if the given number is a solution to the given equation.

Is [`[$proposed_solution]`] a solution to [`[$left]=[$right]\text{?}`]

>> [@DataTable(
  [
    [PGML('[`[$left->TeX]`]'),
     PGML('[`=`]'),
     PGML('[`[$right->TeX]`]'),
    ],
    [PGML('[_]{$lefteval}{3}'),
     PGML('[`\wonder{=}`]'),
     PGML('[_]{$righteval}{3}'),
    ],
  ],
      align => 'rcl',
      valign => 'middle',);@]* <<

[_]{$dropdown}{5}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
